// Example: undo becomes natural with a history of store snapshots
const history = [];

function commit(nextState) {
  history.push(store.getState());
  store.setState(nextState);
}

function undo() {
  const previous = history.pop();
  if (previous) store.setState(previous);
}

function createUndoStack() {
  const past = [];
  let present = null;

  return {
    set(state) {
      if (present !== null) past.push(present);
      present = structuredClone(state);
    },
    undo() {
      if (!past.length) return present;
      present = past.pop();
      return present;
    },
  };
}

